import{_ as d,c as e,a,o as r}from"./app-CEcM0piI.js";const n={};function i(o,t){return r(),e("div",null,t[0]||(t[0]=[a('<p>全称即时模式游戏用户交互界面（IMGUI）在Unity中一般简称为GUI 它是一个代码驱动的UI系统</p><p>必须运行时才能看到，且不能自适应分辨率</p><p>要让gui在不运行时也能看到可以加上特性：<code>[executeaways]</code></p><p><strong>主要作用</strong>： 作为程序员的调试工具，创建游戏内调试工具 为脚本组件创建自定义检视面板 创建新的编辑器窗口和工具以拓展Unity本身（一般用作内置游戏工具）</p><p>制作gui的组件必须继承MonoBehaviour类，并将gui控件在OnGUI生命周期函数中绘制</p><p>它每帧执行相当于是用于专门绘制GUI界面的函数 一般只在其中执行GUI相关界面绘制和操作逻辑 该函数在OnDisable之前LateUpdate之后执行 只要是继承Mono的脚本都可L以在OnGUI中绘制GUI</p><p>gui的窗口起始位置是窗口左上角，xy轴正方形分别是向右向下</p><h3 id="控件" tabindex="-1"><a class="header-anchor" href="#控件"><span>控件</span></a></h3><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>Label</td><td>标签控件，可以显示文字和图片，传入GUIStyle类型来控制gui样式</td></tr><tr><td>Button</td><td>按钮控件</td></tr><tr><td>Toggle</td><td>多选框，返回是否被选中</td></tr><tr><td>TextField</td><td>普通输入框，返回输入框的内容</td></tr><tr><td>PasswordField</td><td>密码输入框，可以传入自定义的字符串用于代替密码字段</td></tr><tr><td>HorizontalSlider</td><td>水平拖动条，返回的是一个浮点类型的当前值</td></tr><tr><td>VerticalSlider</td><td>竖直拖动条</td></tr><tr><td>DrawTexture</td><td>图片绘制</td></tr><tr><td>Box</td><td>框绘制</td></tr><tr><td>Toolbar</td><td>工具栏</td></tr><tr><td>SelectionGrid</td><td>选择网格</td></tr><tr><td>Window</td><td>绘制窗口，传入的委托（函数指针）是创建的窗口中的组件</td></tr><tr><td>ModalWindow</td><td>模态窗口</td></tr><tr><td>Color</td><td>gui默认颜色</td></tr><tr><td>skin</td><td>是一个guistyle的综合体，里面有各种控件的配置，给它设置了style后创建的gui控件都有skin的配置，如果再创建控件的时候更改会使用更改后的配置</td></tr></tbody></table><h3 id="分组" tabindex="-1"><a class="header-anchor" href="#分组"><span>分组</span></a></h3><p>用于批量控制控件位置 可以理解为包裹着的控件加了一个父对象 可以通过控制分组来控制包裹控件的位置 <code>BeginGroup/EndGroup</code>两个函数之间包裹的控件即为一个分组 分组中的控件只能显示在分组的范围内</p><h3 id="滚动列表" tabindex="-1"><a class="header-anchor" href="#滚动列表"><span>滚动列表</span></a></h3><h3 id="guilayout布局" tabindex="-1"><a class="header-anchor" href="#guilayout布局"><span>GUILayout布局</span></a></h3><p>会自动布局其中的控件</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>Begin/EndHorizontal</td><td>声明布局的开始和结束，在这两个函数之间的控件都属于这个布局中</td></tr></tbody></table><h1 id="ngui" tabindex="-1"><a class="header-anchor" href="#ngui"><span>NGUI</span></a></h1><p>NGUI全称下一代用户界面(Next-Gen UI) 它是第三方提供的Unity付费插件 专门用于制作Unity中游戏UI的第三方工具 相对于GUI它更适用于制作游戏UI功能 更方便使用，性能和效率更高 Unity插件：是一种基于Unity规范编写出来的程序，主要用于拓展功能，简单理 解就是别人基于Unity写好的某种功能代码，我们可以直接用来处理特定的游戏 逻辑</p><p>![[Pasted image 20250226110746.png]]</p><p><strong>Unity最初版本~Unity4.6版本</strong> Unity官方只提供了GUI用于游戏UI的开发 所以更为高级和方便的NGUI是做UI的不二选择</p><p><strong>Unity4.6版本以后</strong> Unity官方招募NGUI作者加入Unity，协助Unity开发出UGUI系统用于游戏UI功能开发 由于UGUI刚推出后功能不够完善，所以经历了较长的过渡期，几乎到Unity5的时代才开始正式全面普及</p>',20)]))}const p=d(n,[["render",i]]),h=JSON.parse('{"path":"/game/unity/6/","title":"6 IMGUI","lang":"zh-CN","frontmatter":{"title":"6 IMGUI","createTime":"2025/06/22 11:08:34","permalink":"/game/unity/6/"},"readingTime":{"minutes":2.96,"words":888},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/游戏/Unity/6 IMGUI.md","headers":[]}');export{p as comp,h as data};
